ENUM_ICE_CRASH_SUBSTATE_END   <-3 ;			  //막타

ENUM_ICE_CRASH_TIMER_SPIN <- 0;
ENUM_ICE_CRASH_MULTI_HIT  <- 1;

VAR_ICE_CRASH <-0

function checkExecutableSkill_IceCrash(obj)
{

