			//appendage.setValid(false);
			return true;
		}
	}	
	
	if(skill.isInCoolTime()) return false;
	
	local b_useskill = obj.sq_IsUseSkill(SKILL_ICEROAD);

	if(b_useskill) {
		obj.sq_IntVectClear();
