	}

	local obj = appendage.getParent();
	
	if(!obj)
	{
		appendage.setValid(false);
		return;
	}

	if(appendage.sq_var.size_vector() == 0)
	{
		appendage.setValid(false);
		return;
	}
	
	if(appendage.sq_var.get_vector(1) == 0)
	{
		local isActiveStatus = sq_IsValidActiveStatus(obj, ACTIVESTATUS_SLOW);
		
