	print( " hitCnt	:" + hitCnt);
	
	local object = sq_GetObjectByObjectId(obj, id);
	obj.sq_var.clear_obj_vector();
	obj.sq_var.push_obj_vector(object);
	
	
	local pAni = obj.getCurrentAnimation();	
