	obj.getVar("hitCnt").push_vector(hitCnt);
	obj.getVar("hitCnt").push_vector(1);
	
	obj.getVar("end").clear_vector();
	obj.getVar("end").push_vector(0);
	
	local pAttack = sq_GetCurrentAttackInfo(obj);
