	else if(subState == ENUM_MAGIC_CANNON_SUBSTATE_CHARGE) {	// 점프 중 시전 - 준비 동작 끝
		local isHorizon = sq_IsKeyDown(OPTION_HOTKEY_MOVE_LEFT, ENUM_SUBKEY_TYPE_ALL) || sq_IsKeyDown(OPTION_HOTKEY_MOVE_RIGHT, ENUM_SUBKEY_TYPE_ALL);
