		local increaseDamageRate = sq_GetIntData(obj, SKILL_DIEHARD, SKL_STATIC_INT_IDX_0); 
		
		//increaseDamageRate.tofloat() / 100.0;
		damageRate = damageRate + increaseDamageRate;
	}
	
	return damageRate;
}

