function onAfterSetState_Throw(obj, state, datas, isResetTimer)
{
	local skillIndex = obj.getThrowIndex();
	
	if (skillIndex == SKILL_ELEMENTAL_CHANGE)
	{
		onAfterSetState_ElementalChange(obj, state, datas, isResetTimer);
		
