		//
		
		// 여기서 append 작업		
		CNSquirrelAppendage.sq_Append(appendage, obj, obj);
		//		
		
		// Awakening.skl 스킬레벨 테이블
		//SL_PERFECT_CHANGE_HP <- 0 // (0) 완전 변신체 HP 
