// 이것이 그 리턴값이다..

function isPriestFlow(obj, state)
{
	if(!obj) return true;
 // 이곳에서 true를 리턴하면 irdcharacter:: 쪽으로 가는것이 아니라 cnpriest 쪽으로 가게 됩니다..
	if(!isGrowTypeAvenger(obj)) // 어벤저가 아닌 경우 무조건 flowpriest로
