function procEnterDevilStrike(obj, keyIndex, attackIndex)
{
	if(!obj) return;
	
	local bEnable = isEnterDevilStrike(obj, keyIndex, attackIndex);
	
	if(bEnable) {					
		// 악마게이지를 깎아준다..
