							leve_column = 0;
						}

						local consumeV = getDevilStrikeConsumeValue(obj, leve_column);
						consumeDevilGauge(obj, consumeV);


						// x키의 경우 
						// 같은 state내에서 발생하는 경우 어택인덱스를 늘려준다..
						local resultAttackIndex = attackIndex;
						
						if(keyIndex == E_ATTACK_COMMAND) {
