							//print("resultAttackIndex:" + resultAttackIndex);
							local Index = resultAttackIndex;
							Index = Index + 1;
							if(Index > 2)
								Index = 0;
							
							obj.getVar("devilStrike").set_vector(2, Index);
						}
					
						if(resultAttackIndex == 0) { // attack (x)
							leve_column = 1;
						}
						else if(resultAttackIndex == 1) { // jump (c)
							leve_column = 2;
						}
