						//iKeyList[1] = E_JUMP_COMMAND;
						//iKeyList[2] = E_SKILL_COMMAND;
						
						//local firstAttackRate = obj.sq_getBonusRateWithPassive(SKILL_DEVILSTRIKE, state, 0, 1.0);
						
