						obj.sq_binaryData_startWrite();
						obj.sq_binaryData_writeDword(attack_bonus_rate); // 데빌스트라이커의 공격력(%)
						
						obj.sq_p00_sendCreatePassiveObjectPacket(24104 + resultAttackIndex, 0, 0, 1, 0);
						
						// 쿨타임 세팅
						var_devil.get_ct_vector(0).Reset();
