{
	if(!obj) return;
	if(!animation) return;
	
	if(isAvengerAwakenning(obj)) { // 각성 둠스가디언 변신 후라면 setcurrentanimation 되는 모든 animation은 투명도 조절관련 플래그를 오프시킵니다..
