					obj.sq_setShake(obj, 1, 200); // 지진을 일으킨다.. 
					obj.getVar().set_vector(2, 1); // 2번플래그를 1로 바꾼다 왜냐하면 딱 한번만 이안으로 들어와야하기때문에..
				}
			}
		}
		
		
		return;
