		}
		else {
			obj.getVar().set_vector(3, 1); // 대쉬이동 플래그 3 - 이동불가지역을 만났을 때 더이상 이동을 못하도록 하기 위함입니다..		
		}	
		
		obj.getVar().set_vector(2, posX); // 도착점
	}
	else {		
	
