		ti.setParameter(60, -1);
		ti.resetInstant(0);
	}
	
	// 다단히트 설정
	local multiT = sq_var.get_timer_vector(1);
	
	if (multiT.isOnEvent(currentT) == true)
		obj.resetHitObjectList();
	
	
}

