function isGrabable_PowerOfDarkness(obj)
{
	local sq_var = obj.getVar();
	local i=0;	
	local objectsSize = sq_var.get_obj_vector_size();		
	
	if(objectsSize == 0)
		return false;	
		
	for(;i<objectsSize;++i)
	{				
