	local currentFrameIndex = main_gauge_b.GetCurrentFrameIndex();
	sq_DrawSpecificFrameEffect_SIMPLE(main_gauge_b, x, y, currentFrameIndex, baseRGB, alpha, false);
	//sq_drawCurrentFrame(main_gauge_b, x, y, false);
	
