function setCustomData_po_CreatorWoodFence(obj,recive)
{

	if (!obj) return;

	local time = recive.readDword();
	
	local chr = obj.getTopCharacter();
	
	if (chr)
	{
		 local map = sq_GetMap(chr);
		 
		 if (map)
		 {
			map.recalcAStarAttributesByMovableObject(obj, false);
		 }
