		else if(state == 1)
		{
			print("state:" + state + " appendage.getTimer().Get():" + appendage.getTimer().Get());
			startT = 200;
			endT = 50;
			effectT = 200;
			effectType = GRAPHICEFFECT_LINEARDODGE;
			rgb = sq_RGB(255, 255, 255);
		}
