	else if(appendage.sq_GetSkillIndex() == SKILL_DIEHARD)
	{
		if(state == 0)
		{
			startT = 50;
			endT = 200;
			effectT = 700;
			effectType = GRAPHICEFFECT_LINEARDODGE;
			rgb = sq_RGB(255, 255, 255);
		}
